43	// CheckACQuality parses acceptance text and computes a verifiability score.
44	// verifiable_count = items classified as test-name | symbol | negative |
45	// build-gate | mechanical. score = verifiable_count / total; 0 when total == 0.
46	func CheckACQuality(acceptance string, threshold float64) ACQualityResult {
47		items := accheck.ParseAcceptance(acceptance)
48		total := len(items)
49		result := ACQualityResult{
50			Threshold: threshold,
51			Total:     total,
52			Items:     make([]ACQualityItem, 0, total),
53		}
54		if total == 0 {
55			// No ACs to evaluate: pass vacuously. The gate targets beads that have
56			// acceptance criteria but those criteria are all prose; absence of ACs
57			// is a separate quality signal handled by other checks.
58			result.PassesThreshold = true
59			return result
60		}
61		for _, item := range items {
62			verifiable := item.Kind != accheck.KindProse
63			result.Items = append(result.Items, ACQualityItem{
64				AC:         item.AC,
65				Text:       item.Text,
66				Kind:       string(item.Kind),
67				Verifiable: verifiable,
68			})
69			if verifiable {
70				result.VerifiableCount++
71			} else {
72				result.ProseCount++
73			}
74		}
75		result.Score = float64(result.VerifiableCount) / float64(total)
76		result.PassesThreshold = result.Score >= threshold
77		return result
78	}
