116	// NewACQualityPreClaimGate returns a PreClaimIntakeHook that checks the bead's
117	// AC verifiability score before any execution attempt. In WARN-ONLY mode, low
118	// scores append warning evidence and still proceed to the inner hook. In
119	// BLOCK/factory mode, low scores mark the bead ineligible and return
120	// PreClaimIntakeOperatorRequired. When score >= threshold, inner is called (if
121	// non-nil) or PreClaimIntakeActionableAtomic is returned.
122	//
123	// This gate is deterministic: no LLM call is made. It should be chained
124	// before the LLM-based intake hook so that beads with low-quality ACs never
125	// burn drain budget.
126	func NewACQualityPreClaimGate(store BeadACQualityStore, mode string, threshold float64, inner PreClaimIntakeHook) PreClaimIntakeHook {
127		return func(ctx context.Context, beadID string) (PreClaimIntakeResult, error) {
128			if ctx != nil {
129				if err := ctx.Err(); err != nil {
130					return PreClaimIntakeResult{}, err
131				}
132			}
133			b, err := store.Get(ctx, beadID)
134			if err != nil {
135				// Fail-open: delegate to inner hook on store read failure.
136				if inner != nil {
137					return inner(ctx, beadID)
138				}
139				return PreClaimIntakeResult{Outcome: PreClaimIntakeActionableAtomic}, nil
140			}
141			result := CheckACQuality(b.Acceptance, threshold)
142			if !result.PassesThreshold {
143				block := isReadinessBlockingMode(mode)
144				_ = MarkBeadACQualityLow(store, beadID, result, block)
145				if !block {
146					if inner != nil {
147						return inner(ctx, beadID)
148					}
149					return PreClaimIntakeResult{Outcome: PreClaimIntakeActionableAtomic}, nil
150				}
151				return PreClaimIntakeResult{
152					Outcome: PreClaimIntakeOperatorRequired,
153					Reason:  "ac-quality:needs-refinement",
154					Detail: fmt.Sprintf(
155						"score %.2f below threshold %.2f (%d/%d verifiable ACs)",
156						result.Score, threshold, result.VerifiableCount, result.Total),
157				}, nil
158			}
159			if inner != nil {
160				return inner(ctx, beadID)
161			}
162			return PreClaimIntakeResult{Outcome: PreClaimIntakeActionableAtomic}, nil
163		}
164	}
